mapper.insert:
INSERT INTO inspection_results (
    plan_id, executed_date, executed_by, summary_judge,
    summary_note, next_recommended_date, approval_status
) VALUES (
    #{planId}, #{executedDate}, #{executedBy}, #{summaryJudge},
    #{summaryNote}, #{nextRecommendedDate}, #{approvalStatus}
)

INSERT INTO inspection_items_results (
    result_id, item_id, judge, measured_value, note
) VALUES (
    #{resultId}, #{itemId}, #{judge}, #{measuredValue}, #{note}
)

mapper.select:
SELECT COUNT(*)
FROM inspection_results r
JOIN inspection_plans p ON r.plan_id = p.plan_id


        AND r.executed_date >= #{dateFrom}


        AND r.executed_date <= #{dateTo}


        AND r.approval_status = #{status}

SELECT r.*, p.planned_date, p.person_code, e.equipment_name, e.equipment_code, t.inspection_kind, t.template_name FROM inspection_results r JOIN inspection_plans p ON r.plan_id = p.plan_id LEFT JOIN equipment e ON p.equipment_code = e.equipment_code LEFT JOIN inspection_template t ON p.template_id = t.template_id
AND r.executed_date >= #{dateFrom}
AND r.executed_date <= #{dateTo}
AND p.team_code = #{team}
AND r.approval_status = #{status}
ORDER BY r.executed_date DESC, r.result_id DESC
